import{_ as e,c as i,o as l,ae as a}from"./chunks/framework.Byi7L62k.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"docs/legal/hipaa.md","filePath":"docs/legal/hipaa.md"}'),r={name:"docs/legal/hipaa.md"};function o(d,t,n,s,c,p){return l(),i("div",null,t[0]||(t[0]=[a('<h2 id="hipaa" tabindex="-1">HIPAA <a class="header-anchor" href="#hipaa" aria-label="Permalink to &quot;HIPAA&quot;">​</a></h2><ul><li>The effective date of this policy is Feb 2, 2026.</li></ul><table tabindex="0"><thead><tr><th>Page</th><th>Name</th></tr></thead><tbody><tr><td>1</td><td><a href="https://docs.google.com/document/d/1_8Bun4cIYcUHez45S2C284O0SFBdDHE0qgj3kmuZ85s/edit?tab=t.0#heading=h.daqz3gss2y0t" target="_blank" rel="noreferrer">Privacy Policy</a></td></tr><tr><td>2</td><td><a href="https://docs.google.com/document/d/1Mef6MyZmygUNmyUSel8dCZwAkR5g-hJ1XqKPXXaGqfQ/edit?tab=t.0#heading=h.m2aul5nogrys" target="_blank" rel="noreferrer">Security Policy</a></td></tr><tr><td>3</td><td><a href="https://docs.google.com/document/d/1EeSBn41zq8CESAfQjOav2exFDcduJhK3nuCBl39qvEQ/edit?tab=t.0#heading=h.5jzmr17of0cx" target="_blank" rel="noreferrer">Breach Notification Policy</a></td></tr><tr><td>4</td><td><a href="https://docs.google.com/document/d/16GUSuUFlNbUjltXfpwohbrBlW5NRc8q6ZiH5iy9VFJY/edit?tab=t.0#heading=h.9kdskf3tpnzd" target="_blank" rel="noreferrer">Risk Analysis</a></td></tr><tr><td>5</td><td><a href="https://docs.google.com/document/d/1eEBF0RzRckDPwA_JUnXagM4mSx8BdLWE4YpC5d7tI0k/edit?tab=t.0#heading=h.rho2zomzw7an" target="_blank" rel="noreferrer">Notice of Privacy Practices (NPP)</a></td></tr><tr><td>6</td><td><a href="https://docs.google.com/document/d/1OhmALieNE6L2BJGoQ0--5MTWN4RcnA4gIOpb6HwKlg8/edit?tab=t.0#heading=h.cyhp41e862nj" target="_blank" rel="noreferrer">Business Associate Agreement (BAA)</a></td></tr><tr><td>7</td><td><a href="https://docs.google.com/document/d/1-jzTbP8j4VO3onSE95LSwRoUqee9zD5_ugiQweBw0Fc/edit?tab=t.0#heading=h.21z8f4948tvw" target="_blank" rel="noreferrer">Training Log</a></td></tr><tr><td>8</td><td><a href="https://docs.google.com/document/d/1YqZwHOWf-Ijrmd0dRnnH6ilAwaF3mBWVhB8IYsjKEnk/edit?tab=t.0#heading=h.f6wuzoi1o90n" target="_blank" rel="noreferrer">Employee Confidentiality Agreement</a></td></tr></tbody></table><table tabindex="0"><thead><tr><th>Acronyms</th><th>Full Name</th></tr></thead><tbody><tr><td>PHI</td><td>Protected Health Information</td></tr><tr><td></td><td></td></tr><tr><td></td><td></td></tr><tr><td></td><td></td></tr><tr><td></td><td></td></tr></tbody></table><ol><li>What is HIPAA?</li></ol><ul><li>Health Insurance Portability and Accountability Act (HIPAA) is a U.S. law that protects sensitive patient health information from being disclosed without the patient’s consent or knowledge.</li></ul><p>HIPAA protects PHI (Protected Health Information)</p><p>PHI includes things like:</p><ul><li>Name</li><li>Date of birth</li><li>Medical records</li><li>Diagnosis or conditions</li><li>Lab results</li><li>Insurance info</li><li>Appointment records</li><li>Device health readings</li><li>Any health data tied to an identifiable person</li></ul><p>Example:</p><table tabindex="0"><thead><tr><th>Data</th><th>Protected</th></tr></thead><tbody><tr><td>Heart rate without identity</td><td>❌ No</td></tr><tr><td>Heart rate + name/email</td><td>✅ Yes</td></tr><tr><td>Medication list</td><td>✅ Yes</td></tr><tr><td>Appointment reminders</td><td>✅ Yes</td></tr></tbody></table><ol start="2"><li>When an App Must Be HIPAA Compliant</li></ol><p>HIPAA usually applies if your app works with:</p><ul><li>Healthcare providers</li><li>Health insurers</li><li>Healthcare clearinghouses</li><li>Business associates of the above</li></ul><p>Example:</p><p>Your caregiver or health monitoring app (like the one you mentioned previously with the Independa Health Hub) may fall under Business Associate if it processes patient data for providers.</p><ol start="3"><li>Main HIPAA Requirements</li></ol><p>HIPAA compliance generally requires:</p><ul><li>Administrative Safeguards</li><li>Risk assessments</li><li>Security policies</li><li>Employee training</li><li>Incident response plans</li><li>Physical Safeguards</li><li>Secure servers</li><li>Restricted physical access</li><li>Device protections</li><li>Technical Safeguards</li><li>Encryption (data at rest &amp; in transit)</li><li>Access control</li><li>Authentication</li><li>Audit logs</li><li>Automatic logoff</li></ul><p>Example:</p><p>Requirement Example</p><ul><li>Encryption TLS for API calls</li><li>Access control Role-based permissions</li><li>Audit logs Track who viewed patient data</li><li>Authentication MFA for staff accounts</li></ul><ol start="4"><li>Other Compliance Standards Apps Often Need</li></ol><p>Depending on your users and location, you may also need other regulations.</p><p>1️⃣ General Data Protection Regulation (GDPR)</p><p>Applies if any EU users use your app.</p><p>Requirements:</p><ul><li>User consent for data collection</li><li>Right to delete data</li><li>Data portability</li><li>Breach notification</li><li>Privacy by design</li><li>Right to know what data is collected Even U.S. companies must comply if they have EU users.</li></ul><p>2️⃣ California Consumer Privacy Act (CCPA)</p><p>Applies to many companies with California users.</p><p>Users must be able to:</p><ul><li>See collected data</li><li>Request deletion</li><li>Opt-out of selling data</li></ul><p>The newer version is California Privacy Rights Act.</p><p>3️⃣ Children&#39;s Online Privacy Protection Act (COPPA)</p><p>If your app collects data from children under 13, you must:</p><ul><li>Get parental consent</li><li>Limit data collection</li><li>Protect child privacy</li></ul><p>4️⃣ Payment Card Industry Data Security Standard</p><p>Needed if your app processes:</p><ul><li>credit cards</li><li>payments</li><li>subscriptions</li><li>Example:</li><li>Stripe</li><li>PayPal</li><li>in-app purchases</li></ul><p>5️⃣ SOC 2</p><p>Not a law but important for SaaS platforms.</p><ul><li>Focuses on:</li><li>security</li><li>availability</li><li>confidentiality</li><li>processing integrity</li><li>privacy</li><li>Hospitals and enterprise clients often require SOC 2.</li></ul><ol start="6"><li>Typical Compliance Stack for Health Apps</li></ol><p>Most health or caregiver apps follow something like:</p><table tabindex="0"><thead><tr><th>Compliance</th><th>Reason</th></tr></thead><tbody><tr><td>HIPAA</td><td>Health data protection</td></tr><tr><td>SOC 2</td><td>Enterprise security</td></tr><tr><td>GDPR</td><td>EU users</td></tr><tr><td>CCPA / CPRA</td><td>California users</td></tr><tr><td>PCI DDS</td><td>Payments</td></tr></tbody></table><ol start="7"><li>Common Technical Requirements for Compliance</li></ol><p>Apps usually implement:</p><ul><li>TLS encryption</li><li>Encrypted databases</li><li>Access control (RBAC)</li><li>Audit logging</li><li>Secure backups</li><li>Data retention policies</li><li>User consent tracking</li><li>Data deletion mechanisms</li></ul>',48)]))}const m=e(r,[["render",o]]);export{u as __pageData,m as default};
